import Atividades from "./Atividades";
import { useState } from "react";
import { useParams, Link } from "react-router-dom";
import styled from "styled-components";
import { getInfos, getAtividades, setCompletion } from "../Dados/Dados";
import { useNavigate } from "react-router-dom";
import PaginaId from "../styled";

export default function TelaAtividade() {
  const { nomeAtividade, nivel, passo } = useParams();
  const [infos, def, texto] = getInfos(nomeAtividade, nivel, passo);

  const [sound, setSound] = useState(new Audio());
  const [sel, setSel] = useState(null);
  const [feedback, setFeedback] = useState("");

  function playAudio(elemento) {
    setSel(elemento);
    sound.pause();

    const musica = "/Audios/" + elemento.arquivo;
    const new_sound = new Audio(musica);
    new_sound.play();
    setSound(new_sound);

    if (elemento.corr === 1) {
      setFeedback("✅ Resposta correta!");
    } else {
      setFeedback("❌ Resposta incorreta! Tente novamente.");
    }
  }

  function press_Prox() {
    setSel(null);
    sound.pause();
    setFeedback("");
  }

  const proxButton = () => {
    if (sel == null || sel.corr !== 1) return <></>;
    return (
      <Link
        to={{
          pathname: `/atividade/${nomeAtividade}/${nivel}/${Number(passo) + 1}`,
        }}
        onClick={press_Prox}
      >
        <button>Próximo</button>
      </Link>
    );
  };

  return (
    <>
      <PaginaId>
        {nivel}.{passo}
      </PaginaId>
      <Page>
        <Header>Vamos Cirandar</Header>
        <Titulo>{getAtividades()[nomeAtividade]}</Titulo>
        <Dado>
          <Play
            name="play-circle"
            onClick={() => {
              playAudio(def);
            }}
          ></Play>{" "}
          Ouça o início da Ciranda Cirandinha
        </Dado>
        <Pergunta>{texto}</Pergunta>
        <Alternativas>
          {infos.map((elemento) => (
            <Alternativa
              key={elemento.opcao}
              style={{ color: elemento === sel ? (elemento.corr ? "green" : "red") : "black" }}
              onClick={() => playAudio(elemento)}
            >
              {elemento.opcao}
            </Alternativa>
          ))}
        </Alternativas>
        {feedback && <Feedback>{feedback}</Feedback>}
        <Navegacao>
          <Link to={{ pathname: `/atividades` }}>
            <button>Voltar</button>
          </Link>
          {proxButton()}
        </Navegacao>
      </Page>
    </>
  );
}

// Estilização dos componentes
const Navegacao = styled.ul`
  width: 100%;
  box-sizing: border-box;
  padding: 20px;
  position: absolute;
  bottom: 25px;
  display: flex;
  justify-content: space-between;
`;

const Page = styled.main`
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
`;

const Header = styled.h1`
  width: 100%;
  height: auto;
  margin: 20px 0;
  text-align: center;
  color: #0070c0;
  font-size: 40px;
`;

const Titulo = styled.h2`
  width: 100%;
  height: auto;
  margin: 15px 0;
  text-align: center;
  color: green;
  font-size: 30px;
`;

const Dado = styled.p`
  width: auto;
  height: 50px;
  color: rgb(7, 166, 219);
  font-size: 30px;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const Pergunta = styled.p`
  width: auto;
  height: 50px;
  font-size: 30px;
  color: green;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const Play = styled("ion-icon")`
  font-size: 50px;
  &:hover {
    color: green;
  }
`;

const Alternativas = styled.ul`
  width: 100%;
  height: auto;
  display: flex;
  align-items: center;
  justify-content: space-around;
`;

const Alternativa = styled.p`
  font-size: 50px;
  margin: 50px;
  cursor: pointer;
`;

const Feedback = styled.p`
  font-size: 24px;
  margin-top: 20px;
  color: ${(props) => (props.children.includes("❌") ? "red" : "green")};
`;
